// Reproducible one-shot path used by this demo.
// The same topic API can connect separate inferlets on a shared engine.
let idea = generate_with(SYS_IDEA, &seed).await?;

let plot_sub = messaging::subscribe("demo-idea-to-plot");
messaging::broadcast("demo-idea-to-plot", idea.trim());
let idea = plot_sub.get_async().await.unwrap();

let plot = generate_with(SYS_PLOT, &format!("Concept: {idea}")).await?;
let combined = format!("{idea}\n\nPlot:\n{}", plot.trim());

let dialogue_sub = messaging::subscribe("demo-plot-to-dialogue");
messaging::broadcast("demo-plot-to-dialogue", &combined);
let plot_context = dialogue_sub.get_async().await.unwrap();

let dialogue = generate_with(SYS_DIALOGUE, &format!("Story so far:\n{plot_context}")).await?;
